terraform_snippet:
# Security Defaults shortcut
resource "azuread_directory_setting" "defaults" {
  display_name = "Security Defaults"
  template_id  = "62375ab9-6b52-47ed-826b-58e47e0e304b"
}

resource "azuread_conditional_access_policy" "admin_mfa" {
  display_name = "Require MFA for admins"
  state        = "enabled"
  conditions { users { included_roles = ["62e90394-69f5-4237-9190-012177145e10"] } applications { included_applications = ["All"] } }
  grant_controls { operator = "OR" built_in_controls = ["mfa"] }
}
